using System;

public class PlayerStats : MonoBehaviour
{
    public int maxHealth = 100;
    public int currentHealth { get; private set; }

    public int startCurrency = 500;
    public int currentCurrency { get; private set; }
    
    void Start()
    {
        // Initialize player's health and currency
        currentHealth = maxHealth;
        currentCurrency = startCurrency;
    }

    // Method to take damage
    public void TakeDamage(int amount)
    {
        currentHealth -= Math.Max(amount, 0);
        if (currentHealth <= 0) Die();
    }

    // Method to add currency
    public bool AddCurrency(int amount)
    {
        if (amount < 0) return false;  // Can't add negative amount of currency
        
        currentCurrency += amount;
        return true;
    }
    
    private void Die()
    {
        // Handle death here, maybe send message to some DeathHandler
    }
}